arguments.command:
cd /tmp/symbols
# Use dynamic symbols to resolve addresses
# First, dump all FUNC symbols sorted by address
nm -D --defined-only libmonosgen-2.0.so 2>&1 | grep ' T \| t ' | sort | awk '
{
  addr = strtonum("0x" $1);
  name = $3;
  addrs[NR] = addr;
  names[NR] = name;
  count = NR;
}
END {
  # Addresses to look up
  split("0x222098 0x222234 0x19bac0 0x19bc14", targets, " ");
  for (t in targets) {
    target = strtonum(targets[t]);
    best = "";
    best_addr = 0;
    for (i = 1; i <= count; i++) {
      if (addrs[i] <= target && addrs[i] > best_addr) {
        best_addr = addrs[i];
        best = names[i];
      }
    }
    printf "0x%x -> %s+0x%x (at 0x%x)\n", target, best, target - best_addr, best_addr;
  }
}' 2>&1

