arguments.command:
cd /tmp/symbols
# Look for function prologues (stp x29, x30) near target addresses by disassembling
# For 0x222098 - scan backwards to find function start
python3 << 'EOF'
import subprocess

def find_function_start(so_file, target_addr, search_back=0x200):
    """Find the nearest function prologue before target_addr by looking for stp x29, x30 patterns"""
    start = max(0, target_addr - search_back)
    result = subprocess.run(
        ['aarch64-linux-gnu-objdump', '-d', so_file,
         f'--start-address=0x{start:x}', f'--stop-address=0x{target_addr+4:x}'],
        capture_output=True, text=True
    )

    # Look for stp x29, x30 (function prologue) or pac instructions
    prologue_addr = None
    for line in result.stdout.split('\n'):
        line = line.strip()
        if ':' in line and ('stp\tx29, x30' in line or 'paciasp' in line):
            try:
                addr_str = line.split(':')[0].strip()
                addr = int(addr_str, 16)
                if addr <= target_addr:
                    prologue_addr = addr
            except ValueError:
                pass
    return prologue_addr

targets = {
    'libmonosgen-2.0.so': [
        (0x222098, '#01'),
        (0x222234, '#02'),
        (0x19bac0, '#03'),
        (0x19bc14, '#06'),
    ]
}

for lib, addrs in targets.items():
    for target, frame in addrs:
        func_start = find_function_start(lib, target, search_back=0x500)
        if func_start:
            print(f"Frame {frame}: 0x{target:x} -> function likely starts at 0x{func_start:x} (offset +0x{target-func_start:x})")
        else:
            print(f"Frame {frame}: 0x{target:x} -> no prologue found within search range")
EOF

